#ifndef TREE_RULES_H
#define TREE_RULES_H

/*
 * Predict LED brightness based on sensor inputs and time features
 * 
 * Parameters:
 *   ambient_light: Ambient light level from LDR (lux, typically 0-1000)
 *   motion_detected: Motion detection from PIR (0 or 1)
 *   sin_hour: Sine component of hour (sin(2*PI*hour/24))
 *   cos_hour: Cosine component of hour (cos(2*PI*hour/24))
 *   time_period: Time period code (0=Early Morning, 1=Morning, 2=Afternoon, 3=Evening, 4=Night)
 * 
 * Returns:
 *   Predicted LED brightness (0-100%)
 */
float predict_brightness(float ambient_light, int motion_detected, float sin_hour, float cos_hour, int time_period) {
  // PLACEHOLDER LOGIC - Simple rule-based prediction
  // Replace this entire function with your trained decision tree
  
  float brightness = 50.0f;  // Base brightness
  
  // Adjust based on ambient light (inverse relationship)
  brightness += (1000.0f - ambient_light) / 20.0f;
  
  // Boost if motion detected
  if (motion_detected == 1) {
    brightness += 15.0f;
  }
  
  // Time period adjustments
  if (time_period == 4) {  // Night
    brightness += 10.0f;
    // Special case: Night + High ambient light = Lower brightness
    if (ambient_light > 500.0f) {
      brightness = 25.0f;  // Override to low brightness
    }
  } else if (time_period == 2) {  // Afternoon
    brightness -= 15.0f;
  }
  
  // Clamp to valid range
  if (brightness < 0.0f) brightness = 0.0f;
  if (brightness > 100.0f) brightness = 100.0f;
  
  return brightness;
}

#endif // TREE_RULES_H
